import React, { useState } from 'react';
import ImageUploader from '../components/ImageUploader';
import ImageCapture from '../components/ImageCapture';

const ImageProject = () => {
  const [class1Image, setClass1Image] = useState(null);
  const [class2Image, setClass2Image] = useState(null);

  const handleImageUploadClass1 = (file) => {
    const reader = new FileReader();
    reader.onload = () => setClass1Image(reader.result);
    reader.readAsDataURL(file);
  };

  const handleImageCaptureClass1 = (imageSrc) => {
    setClass1Image(imageSrc);
  };

  const handleImageUploadClass2 = (file) => {
    const reader = new FileReader();
    reader.onload = () => setClass2Image(reader.result);
    reader.readAsDataURL(file);
  };

  const handleImageCaptureClass2 = (imageSrc) => {
    setClass2Image(imageSrc);
  };

  return (
    <div>
      <h2>Image Project</h2>
      <div className="class-section">
        <h3>Class 1</h3>
        <ImageUploader onImageUpload={handleImageUploadClass1} />
        <ImageCapture onImageCapture={handleImageCaptureClass1} />
        {class1Image && <img src={class1Image} alt="Class 1" />}
      </div>
      <div className="class-section">
        <h3>Class 2</h3>
        <ImageUploader onImageUpload={handleImageUploadClass2} />
        <ImageCapture onImageCapture={handleImageCaptureClass2} />
        {class2Image && <img src={class2Image} alt="Class 2" />}
      </div>
    </div>
  );
};

export default ImageProject;
